package com.auction.client.network;import com.auction.client.screenhandler.Controller;import com.auction.shared.model.auction.AuctionDTO;import com.auction.shared.model.item.ItemDTO;import com.auction.shared.model.order.Order;import com.auction.shared.model.user.UserDTO;import com.auction.shared.response.AuctionResponseDTO;import lombok.Getter;import lombok.Setter;/** * Lớp quản lý phiên làm việc (Session) của người dùng hiện tại ở phía Client. * * <p>Lớp sử dụng các biến {@code static} để lưu trữ thông tin người dùng xuyên suốt * vòng đời của ứng dụng JavaFX, giúp các màn hình khác nhau (như Profile, Wallet) * có thể truy xuất dữ liệu một cách tập trung mà không cần truyền tham số qua lại.</p> */public class SessionManager {  /**   * Đối tượng lưu giữ thông tin của người dùng đang đăng nhập vào hệ thống.   */  public static UserDTO currentUser;  /**   * Đối tượng lưu giữ Id của phiên đấu giá mà người dùng vừa ấn vào.   */  public static String currentAuctionId;  /**   * ĐỐi tượng lưu giữ thông tin của đơn hàng hiện tại.   */  public static Order currentOrder;  /**   * Đối tượng lưu giữ thông tin controller của màn hình trước.   */  public static Controller previousScreen;  public static void setCurrentUser(UserDTO currentUser) {    SessionManager.currentUser = currentUser;  }  public static void setCurrentAuctionId(String currentAuctionId) {    SessionManager.currentAuctionId = currentAuctionId;  }  public static void setCurrentOrder(Order currentOrder) {    SessionManager.currentOrder = currentOrder;  }  public static void setPreviousScreen(Controller previousScreen) {    SessionManager.previousScreen = previousScreen;  }  public static UserDTO getCurrentUser() {    return SessionManager.currentUser;  }  public static String getCurrentAuctionId() {    return SessionManager.currentAuctionId;  }  public static Order getCurrentOrder() {    return SessionManager.currentOrder;  }  public static Controller getPreviousScreen() {    return SessionManager.previousScreen;  }}